bash -lc 'ca=$(sysctl -n net.ipv4.conf.all.send_redirects 2>/dev/null || echo);
          cd=$(sysctl -n net.ipv4.conf.default.send_redirects 2>/dev/null || echo);
          if [[ "$ca" == "0" && "$cd" == "0" ]]; then
            echo "all=0 default=0"; exit 0;
          fi;
          if grep -RqsE "^\s*net\.ipv4\.conf\.(all|default)\.send_redirects\s*=\s*0\b" /etc/sysctl.conf /etc/sysctl.d; then
            echo "persisted=0"; exit 0;
          fi;
          echo "all=$ca default=$cd"; exit 1'

