bash -lc ' line=$(grep -Pi "^[[:space:]]*auth[[:space:]]+(required|requisite)[[:space:]]+pam_wheel\.so.*(use_uid|group=)" /etc/pam.d/su | head -n1); if [ -z "$line" ]; then
  echo "group=none | exclusions=none";
  exit 1;
fi; grp=$(echo "$line" | sed -n "s/.*group=\([^[:space:]]*\).*/\1/p"); [ -z "$grp" ] && grp="wheel"; users=$(getent group "$grp" | awk -F: "{print \$4}"); [ -z "$users" ] && users="none"; echo "group=$grp | exclusions=$users"; exit 0'

