awk '/^[[:space:]]*PASS_MAX_DAYS[[:space:]]+/ {v=$2}
    END{
      if(v!="" && v<=365) {
        print "PASS_MAX_DAYS=" v; exit 0
      } else {
        print "PASS_MAX_DAYS=" (v=="" ? "undefined" : v); exit 1
      }
    }' /etc/login.defs

