sh -lc 'i=$(useradd -D | awk -F= "/^INACTIVE=/{print \$2}");
        if [ -n "$i" ] && [ "$i" -le 30 ] && [ "$i" -ge 0 ]; then
          echo "INACTIVE=$i";
          exit 0;
        else
          echo "INACTIVE=${i:-undefined}";
          exit 1;
        fi'

bash -lc '
  min=$(awk "/^[[:space:]]*UID_MIN[[:space:]]+/{print \$2}" /etc/login.defs);

  excl_data=$(for u in root admin tux proactiva iacolcoauto ansible_test halt shutdown sync nfsnobody oracle postgres pos alktstwms alktstems; do
    shell=$(getent passwd "$u" | awk -F: "{print \$7}");
    [ -z "$shell" ] && shell="not_found";

    pstat=$(passwd -S "$u" 2>/dev/null | awk "{print \$2}");
    if [ "$pstat" = "L" ]; then
      locked="yes";
    elif [ -z "$pstat" ]; then
      locked="unknown";
    else
      locked="no";
    fi;

    echo "${u}:shell=${shell},locked=${locked}";
  done | paste -sd "; " -);

  awk -F: -v m="$min" \
      -v ex="^(root|admin|tux|proactiva|iacolcoauto|ansible_test|halt|shutdown|sync|nfsnobody|oracle|postgres|pos|alktstwms|alktstems)$" \
      -v re="^(/usr)?/sbin/nologin(/)?$|^(/usr)?/bin/false(/)?$" \
  "
  BEGIN{bad=0}
  (\$3<m && \$1!~ex){
    if (\$7 !~ re) { print \"bad:\" \$1 \":\" \$7; bad=1 }
  }
  END{
    if(bad==0) {
      print \"All system accounts use nologin/false\"
    }
    exit bad
  }
  " /etc/passwd

  echo "exclusions=${excl_data}"
'

